/**
 * Prohibited-risk freeze (Internal policy; 31 CFR §1010.230).
 *
 * Scenario #10 of guides/use-cases.md: an AccountHolder whose
 * risk_level is 'prohibited' may not originate any transaction.
 * Distinct from sanctions-driven blocks — this is internal policy /
 * lawful-order driven. The audit trail (what compelled the
 * promotion to :prohibited) lives in the existing
 * RiskClassification.classification_reason string; no separate
 * lawful_order_freezes table in MVP.
 *
 * Reads `debtor_payment_account.account_holder.risk_level`. If the
 * level is 'prohibited', emits a blocked Control per LedgerAccount
 * on the debtor side. The cap=0 + is_blocked=true combination is
 * what the limits-at-entry check converts into status='rejected'
 * with rejected_rule='prohibited_risk_freeze'.
 *
 * Catalog verdict: FREEZE — modelled as BLOCK with
 * rejected_rule='prohibited_risk_freeze' because the platform's
 * Transaction status enum has no :held state today. The rule
 * surface stays correct; the verdict can be relaxed to :held once
 * Transaction gains that state.
 */
export const handler = async (input) => {
  const debtor = input.debtor_payment_account;
  if (!debtor) return { ledger_accounts: {} };

  const risk = debtor.account_holder && debtor.account_holder.risk_level;
  if (risk !== 'prohibited') return { ledger_accounts: {} };

  const las = debtor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'prohibited_risk_freeze',
      block_reason: 'prohibited_risk_freeze',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
